INSERT INTO public_content_blocks (id, content_key, language, title, body, items_json, published, display_order, created_at, updated_at)
VALUES
('0a000000-0000-4000-8000-000000000001', 'home.hero', 'es', 'Fullstack Developer', 'Desarrollo aplicaciones de punta a punta, con especial foco en backend, arquitectura y diseno de APIs escalables.', '["Fernando G. Ferreyra","Backend-focused | Java / Spring Boot / .NET / APIs"]', TRUE, 60, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000002', 'home.hero', 'en', 'Fullstack Developer', 'I build end-to-end applications with a strong focus on backend development, architecture, and scalable API design.', '["Fernando G. Ferreyra","Backend-focused | Java / Spring Boot / .NET / APIs"]', TRUE, 61, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000003', 'home.about', 'es', 'Recorrido y perfil actual', 'Mas de 15 anos de experiencia tecnica en electronica e informatica me dieron una base practica para diagnosticar fallas, reparar equipos y resolver problemas complejos. Esa trayectoria hoy se complementa con mi formacion como desarrollador y un perfil orientado al desarrollo fullstack.', '["Durante mas de una decada trabaje de forma hands-on en electronica e informatica, interviniendo equipos, analizando fallas y resolviendo problemas reales en hardware, audio, video y entornos de PC.","Con el tiempo traslade esa experiencia al software, complete la Tecnicatura Universitaria en Programacion en UTN FRC y comence a desarrollar aplicaciones web con frontend, backend, APIs y bases de datos.","Hoy consolido un perfil tecnico integral: combino criterio de diagnostico, trabajo practico y una formacion reciente en desarrollo para aportar en proyectos con una mirada completa del problema."]', TRUE, 62, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000004', 'home.about', 'en', 'Background and current profile', 'More than 15 years of technical experience in electronics and IT gave me a practical foundation to diagnose failures, repair equipment, and solve complex problems. Today that path is complemented by my software training and a profile oriented toward fullstack development.', '["For more than a decade I worked hands-on in electronics and IT, intervening equipment, analyzing failures, and solving real problems across hardware, audio, video, and PC environments.","Over time I brought that experience into software, completed the University Programming Technician degree at UTN FRC, and started building web applications across frontend, backend, APIs, and databases.","Today I am consolidating a well-rounded technical profile: I combine diagnostic judgment, practical execution, and recent software training to contribute to projects with a complete view of the problem."]', TRUE, 63, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000005', 'home.technical.electronics', 'es', 'Electronica', 'Experiencia practica en audio y video, hardware de videojuegos, consolas, PC, monitores y arcades, con trabajo directo en diagnostico, reparacion y programacion de memorias.', '["Audio y video","Consolas y hardware de videojuegos","PC, notebooks y perifericos","Monitores y arcades","Programacion de memorias"]', TRUE, 64, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000006', 'home.technical.electronics', 'en', 'Electronics', 'Hands-on experience in audio and video equipment, gaming hardware, consoles, PCs, monitors, and arcade systems, including diagnostics, repair, and memory programming.', '["Audio and video","Consoles and gaming hardware","PCs, laptops, and peripherals","Monitors and arcades","Memory programming"]', TRUE, 65, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000007', 'home.technical.it', 'es', 'Informatica', 'Soporte tecnico, instalacion, mantenimiento y puesta a punto de equipos y entornos de trabajo, con criterio para resolver fallas de hardware, software y conectividad.', '["Instalacion y configuracion","Sistemas operativos","Mantenimiento preventivo","Redes y conectividad","Soporte tecnico"]', TRUE, 66, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000008', 'home.technical.it', 'en', 'IT', 'Technical support, installation, maintenance, and workstation setup with a practical approach to hardware, software, and connectivity issues.', '["Installation and setup","Operating systems","Preventive maintenance","Networking and connectivity","Technical support"]', TRUE, 67, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000009', 'home.technical.development', 'es', 'Desarrollo', 'Desarrollo de aplicaciones web fullstack, trabajando tanto en frontend como en backend, con experiencia en APIs, bases de datos y buenas practicas de desarrollo.', '["Frontend + Backend","APIs","Bases de datos","Buenas practicas","Aprendizaje continuo"]', TRUE, 68, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000010', 'home.technical.development', 'en', 'Development', 'Fullstack web application development across frontend and backend, with experience in APIs, databases, and development practices while building real-project experience.', '["Frontend + Backend","APIs","Databases","Best practices","Continuous learning"]', TRUE, 69, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000011', 'home.work.backend', 'es', 'Backend', 'Java, Spring Boot, .NET, diseno de APIs, seguridad y logica de negocio para servicios mantenibles.', '["88"]', TRUE, 70, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000012', 'home.work.backend', 'en', 'Backend', 'Java, Spring Boot, .NET, API design, security, and business logic for maintainable services.', '["88"]', TRUE, 71, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000013', 'home.work.frontend', 'es', 'Frontend', 'Angular, TypeScript, componentes reutilizables, consumo de APIs y resolucion visual orientada a producto.', '["74"]', TRUE, 72, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000014', 'home.work.frontend', 'en', 'Frontend', 'Angular, TypeScript, reusable components, API consumption, and product-oriented visual execution.', '["74"]', TRUE, 73, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000015', 'home.work.data', 'es', 'Data', 'Modelado relacional, consultas SQL, PostgreSQL y persistencia para flujos transaccionales y operativos.', '["70"]', TRUE, 74, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000016', 'home.work.data', 'en', 'Data', 'Relational modeling, SQL querying, PostgreSQL, and persistence for transactional and operational flows.', '["70"]', TRUE, 75, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000017', 'home.work.tools', 'es', 'Herramientas', 'Docker, Git, Maven, Postman y tooling de desarrollo para entornos reproducibles y trabajo diario.', '["76"]', TRUE, 76, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000018', 'home.work.tools', 'en', 'Tools', 'Docker, Git, Maven, Postman, and daily development tooling for reproducible environments.', '["76"]', TRUE, 77, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000019', 'skills.hero', 'es', 'Stack tecnico organizado por areas clave.', 'Tecnologias, herramientas y capacidades de trabajo organizadas en un flujo visual continuo, claro y profesional.', '["Enfoque tecnico","Stack por areas","Cada fila reune tecnologias o habilidades relacionadas dentro del mismo lenguaje visual, con movimiento suave y lectura rapida."]', TRUE, 80, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('0a000000-0000-4000-8000-000000000020', 'skills.hero', 'en', 'Technical stack organized by core areas.', 'Technologies, tools, and working capabilities organized in a continuous, clear, and professional visual flow.', '["Technical focus","Stack by area","Each lane groups related technologies or capabilities within the same visual language, with subtle motion and quick scanning."]', TRUE, 81, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
